CREATE TYPE "CartStatus" AS ENUM ('ACTIVE', 'CHECKED_OUT');
CREATE TYPE "OrderStatus" AS ENUM ('PENDING_CONFIRMATION', 'CONFIRMED', 'PROCESSING', 'READY_FOR_INSTALLATION', 'INSTALLATION_IN_PROGRESS', 'COMPLETED', 'CANCELLED');
CREATE TYPE "InventoryDisposition" AS ENUM ('RESERVED', 'CONSUMED', 'RELEASED');
CREATE TYPE "PaymentMethod" AS ENUM ('COD', 'BANK_TRANSFER');
CREATE TYPE "PaymentStatus" AS ENUM ('PENDING', 'PAID', 'FAILED', 'CANCELLED');
CREATE TYPE "AppointmentStatus" AS ENUM ('SCHEDULED', 'ASSIGNMENT_PENDING', 'ASSIGNED', 'CONFIRMED', 'EN_ROUTE', 'IN_PROGRESS', 'COMPLETED', 'RESCHEDULE_REQUIRED', 'CANCELLED');

CREATE TABLE "addresses" ("id" TEXT NOT NULL, "user_id" TEXT NOT NULL, "recipient_name" TEXT NOT NULL, "phone" TEXT NOT NULL, "line1" TEXT NOT NULL, "line2" TEXT, "ward_name" TEXT NOT NULL, "district_code" TEXT NOT NULL, "district_name" TEXT NOT NULL, "province_code" TEXT NOT NULL, "province_name" TEXT NOT NULL, "postal_code" TEXT, "country_code" TEXT NOT NULL DEFAULT 'VN', "service_area_id" TEXT, "is_default" BOOLEAN NOT NULL DEFAULT false, "archived_at" TIMESTAMP(3), "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "addresses_pkey" PRIMARY KEY ("id"));
CREATE TABLE "carts" ("id" TEXT NOT NULL, "user_id" TEXT NOT NULL, "status" "CartStatus" NOT NULL DEFAULT 'ACTIVE', "currency" TEXT NOT NULL DEFAULT 'VND', "checked_out_order_id" TEXT, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, "version" INTEGER NOT NULL DEFAULT 1, CONSTRAINT "carts_pkey" PRIMARY KEY ("id"), CONSTRAINT "carts_currency_check" CHECK ("currency" = 'VND'), CONSTRAINT "carts_version_check" CHECK ("version" > 0));
CREATE TABLE "cart_items" ("id" TEXT NOT NULL, "cart_id" TEXT NOT NULL, "product_variant_id" TEXT NOT NULL, "service_package_id" TEXT, "quantity" INTEGER NOT NULL, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "cart_items_pkey" PRIMARY KEY ("id"), CONSTRAINT "cart_items_quantity_check" CHECK ("quantity" > 0 AND "quantity" <= 99));
CREATE TABLE "installation_slots" ("id" TEXT NOT NULL, "service_area_id" TEXT NOT NULL, "starts_at" TIMESTAMP(3) NOT NULL, "ends_at" TIMESTAMP(3) NOT NULL, "capacity" INTEGER NOT NULL, "booked_count" INTEGER NOT NULL DEFAULT 0, "is_active" BOOLEAN NOT NULL DEFAULT true, "version" INTEGER NOT NULL DEFAULT 1, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "installation_slots_pkey" PRIMARY KEY ("id"), CONSTRAINT "installation_slots_range_check" CHECK ("ends_at" > "starts_at"), CONSTRAINT "installation_slots_capacity_check" CHECK ("capacity" > 0 AND "booked_count" >= 0 AND "booked_count" <= "capacity"), CONSTRAINT "installation_slots_version_check" CHECK ("version" > 0));
CREATE TABLE "orders" ("id" TEXT NOT NULL, "order_number" TEXT NOT NULL, "user_id" TEXT NOT NULL, "status" "OrderStatus" NOT NULL DEFAULT 'PENDING_CONFIRMATION', "currency" TEXT NOT NULL DEFAULT 'VND', "subtotal" BIGINT NOT NULL, "installation_fee" BIGINT NOT NULL, "shipping_fee" BIGINT NOT NULL, "discount_total" BIGINT NOT NULL DEFAULT 0, "grand_total" BIGINT NOT NULL, "recipient_name" TEXT NOT NULL, "recipient_phone" TEXT NOT NULL, "address_line1" TEXT NOT NULL, "address_line2" TEXT, "ward_name" TEXT NOT NULL, "district_code" TEXT NOT NULL, "district_name" TEXT NOT NULL, "province_code" TEXT NOT NULL, "province_name" TEXT NOT NULL, "postal_code" TEXT, "country_code" TEXT NOT NULL, "service_area_id" TEXT, "idempotency_hash" TEXT NOT NULL, "request_fingerprint" TEXT NOT NULL, "inventory_status" "InventoryDisposition" NOT NULL DEFAULT 'RESERVED', "cancellation_reason" TEXT, "confirmed_at" TIMESTAMP(3), "completed_at" TIMESTAMP(3), "cancelled_at" TIMESTAMP(3), "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, "version" INTEGER NOT NULL DEFAULT 1, CONSTRAINT "orders_pkey" PRIMARY KEY ("id"), CONSTRAINT "orders_money_check" CHECK ("subtotal" >= 0 AND "installation_fee" >= 0 AND "shipping_fee" >= 0 AND "discount_total" >= 0 AND "grand_total" = "subtotal" + "installation_fee" + "shipping_fee" - "discount_total"), CONSTRAINT "orders_currency_check" CHECK ("currency" = 'VND'), CONSTRAINT "orders_version_check" CHECK ("version" > 0));
CREATE TABLE "order_items" ("id" TEXT NOT NULL, "order_id" TEXT NOT NULL, "product_variant_id" TEXT NOT NULL, "service_package_id" TEXT, "product_name" TEXT NOT NULL, "variant_name" TEXT NOT NULL, "sku" TEXT NOT NULL, "service_package_name" TEXT, "quantity" INTEGER NOT NULL, "device_unit_price" BIGINT NOT NULL, "service_unit_price" BIGINT NOT NULL, "unit_price" BIGINT NOT NULL, "line_total" BIGINT NOT NULL, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "order_items_pkey" PRIMARY KEY ("id"), CONSTRAINT "order_items_values_check" CHECK ("quantity" > 0 AND "device_unit_price" >= 0 AND "service_unit_price" >= 0 AND "unit_price" = "device_unit_price" + "service_unit_price" AND "line_total" = "unit_price" * "quantity"));
CREATE TABLE "payments" ("id" TEXT NOT NULL, "order_id" TEXT NOT NULL, "method" "PaymentMethod" NOT NULL, "status" "PaymentStatus" NOT NULL DEFAULT 'PENDING', "amount" BIGINT NOT NULL, "currency" TEXT NOT NULL DEFAULT 'VND', "reference_code" TEXT NOT NULL, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, "version" INTEGER NOT NULL DEFAULT 1, CONSTRAINT "payments_pkey" PRIMARY KEY ("id"), CONSTRAINT "payments_amount_check" CHECK ("amount" >= 0 AND "currency" = 'VND' AND "version" > 0));
CREATE TABLE "installation_appointments" ("id" TEXT NOT NULL, "order_id" TEXT NOT NULL, "service_area_id" TEXT NOT NULL, "installation_slot_id" TEXT NOT NULL, "status" "AppointmentStatus" NOT NULL DEFAULT 'SCHEDULED', "scheduled_start_at" TIMESTAMP(3) NOT NULL, "scheduled_end_at" TIMESTAMP(3) NOT NULL, "customer_note" TEXT, "capacity_released_at" TIMESTAMP(3), "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, "version" INTEGER NOT NULL DEFAULT 1, CONSTRAINT "installation_appointments_pkey" PRIMARY KEY ("id"), CONSTRAINT "installation_appointments_range_check" CHECK ("scheduled_end_at" > "scheduled_start_at" AND "version" > 0));
CREATE TABLE "checkout_attempts" ("id" TEXT NOT NULL, "user_id" TEXT NOT NULL, "idempotency_hash" TEXT NOT NULL, "request_fingerprint" TEXT NOT NULL, "order_id" TEXT, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "checkout_attempts_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "carts_checked_out_order_id_key" ON "carts"("checked_out_order_id"); CREATE UNIQUE INDEX "carts_one_active_per_user" ON "carts"("user_id") WHERE "status" = 'ACTIVE'; CREATE INDEX "carts_user_id_status_idx" ON "carts"("user_id", "status"); CREATE UNIQUE INDEX "cart_items_unique_configuration" ON "cart_items"("cart_id", "product_variant_id", "service_package_id") NULLS NOT DISTINCT; CREATE INDEX "cart_items_cart_id_idx" ON "cart_items"("cart_id"); CREATE UNIQUE INDEX "installation_slots_service_area_id_starts_at_ends_at_key" ON "installation_slots"("service_area_id", "starts_at", "ends_at"); CREATE INDEX "installation_slots_service_area_id_starts_at_is_active_idx" ON "installation_slots"("service_area_id", "starts_at", "is_active"); CREATE UNIQUE INDEX "orders_order_number_key" ON "orders"("order_number"); CREATE UNIQUE INDEX "orders_user_id_idempotency_hash_key" ON "orders"("user_id", "idempotency_hash"); CREATE INDEX "orders_user_id_created_at_idx" ON "orders"("user_id", "created_at"); CREATE INDEX "orders_status_created_at_idx" ON "orders"("status", "created_at"); CREATE INDEX "order_items_order_id_idx" ON "order_items"("order_id"); CREATE INDEX "order_items_product_variant_id_idx" ON "order_items"("product_variant_id"); CREATE UNIQUE INDEX "payments_order_id_key" ON "payments"("order_id"); CREATE UNIQUE INDEX "payments_reference_code_key" ON "payments"("reference_code"); CREATE UNIQUE INDEX "installation_appointments_order_id_key" ON "installation_appointments"("order_id"); CREATE INDEX "installation_appointments_service_area_id_scheduled_start_at_status_idx" ON "installation_appointments"("service_area_id", "scheduled_start_at", "status"); CREATE INDEX "installation_appointments_slot_id_status_idx" ON "installation_appointments"("installation_slot_id", "status"); CREATE UNIQUE INDEX "checkout_attempts_order_id_key" ON "checkout_attempts"("order_id"); CREATE UNIQUE INDEX "checkout_attempts_user_id_idempotency_hash_key" ON "checkout_attempts"("user_id", "idempotency_hash"); CREATE INDEX "addresses_user_id_archived_at_idx" ON "addresses"("user_id", "archived_at");
