UPDATE CASCADE; ALTER TABLE "order_items" ADD CONSTRAINT "order_items_service_package_id_fkey" FOREIGN KEY ("service_package_id") REFERENCES "service_packages"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "payments" ADD CONSTRAINT "payments_order_id_fkey" FOREIGN KEY ("order_id") REFERENCES "orders"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "installation_appointments" ADD CONSTRAINT "installation_appointments_order_id_fkey" FOREIGN KEY ("order_id") REFERENCES "orders"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "installation_appointments" ADD CONSTRAINT "installation_appointments_service_area_id_fkey" FOREIGN KEY ("service_area_id") REFERENCES "service_areas"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "installation_appointments" ADD CONSTRAINT "installation_appointments_installation_slot_id_fkey" FOREIGN KEY ("installation_slot_id") REFERENCES "installation_slots"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "checkout_attempts" ADD CONSTRAINT "checkout_attempts_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "checkout_attempts" ADD CONSTRAINT "checkout_attempts_order_id_fkey" FOREIGN KEY ("order_id") REFERENCES "orders"("id") ON DELETE SET NULL ON UPDATE CASCADE;
